//! Built-in function implementations.

use mlpl_array::{DenseArray, Shape};

use crate::error::RuntimeError;
use crate::math_builtins;

macro_rules! check_arity {
    ($name:expr, $expected:expr, $args:expr) => {
        if $args.len() != $expected {
            return Err(RuntimeError::ArityMismatch {
                func: $name.into(),
                expected: $expected,
                got: $args.len(),
            });
        }
    };
}

/// Dispatch a built-in function call by name.
pub fn call_builtin(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    // Try math/constructor builtins first
    if let Some(result) = math_builtins::try_call(name, args.clone()) {
        return result;
    }
    if let Some(result) = crate::random_builtins::try_call(name, args.clone()) {
        return result;
    }
    match name {
        "iota" => builtin_iota(name, args),
        "shape" => builtin_shape(name, args),
        "rank" => builtin_rank(name, args),
        "reshape" => builtin_reshape(name, args),
        "transpose" => builtin_transpose(name, args),
        "reduce_add" | "reduce_mul" => builtin_reduce(name, args),
        "argmax" => builtin_argmax(name, args),
        "dot" => {
            check_arity!(name, 2, args);
            Ok(args[0].dot(&args[1])?)
        }
        "matmul" => {
            check_arity!(name, 2, args);
            Ok(args[0].matmul(&args[1])?)
        }
        "grid" => crate::grid_builtin::builtin_grid(name, args),
        _ => Err(RuntimeError::UnknownFunction(name.into())),
    }
}

fn builtin_iota(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    if args[0].rank() != 0 {
        return Err(RuntimeError::InvalidArgument {
            func: name.into(),
            reason: format!("expected scalar, got rank {}", args[0].rank()),
        });
    }
    let n = args[0].data()[0] as usize;
    let data: Vec<f64> = (0..n).map(|i| i as f64).collect();
    Ok(DenseArray::from_vec(data))
}

fn builtin_shape(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    let dims: Vec<f64> = args[0].shape().dims().iter().map(|&d| d as f64).collect();
    Ok(DenseArray::from_vec(dims))
}

fn builtin_rank(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    Ok(DenseArray::from_scalar(args[0].rank() as f64))
}

fn builtin_reshape(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 2, args);
    let shape_data = args[1].data();
    let dims: Vec<usize> = shape_data.iter().map(|&d| d as usize).collect();
    Ok(args[0].reshape(Shape::new(dims))?)
}

fn builtin_transpose(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    check_arity!(name, 1, args);
    Ok(args[0].transpose())
}

fn builtin_reduce(name: &str, args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
    if args.len() != 1 && args.len() != 2 {
        return Err(RuntimeError::ArityMismatch {
            func: name.into(),
            expected: 1,
            got: args.len(),
        });
    }
    let (identity, op): (f64, fn(f64, f64) -> f64) = match name {
        "reduce_add" => (0.0, |a, b| a + b),
        "reduce_mul" => (1.0, |a, b| a * b),
        _ => unreachable!(),
    };
    if args.len() == 2 {
        if args[1].rank() != 0 {
            return Err(RuntimeError::InvalidArgument {
                func: name.into(),
                reason: format!("axis must be scalar, got rank {}", args[1].rank()),
            });
        }
        let axis = args[1].data()[0] as usize;
        Ok(args[0].reduce_axis(axis, identity, op)?)
    } else {
        let result = args[0].data().iter().copied().fold(identity, op);
        Ok(DenseArray::from_scalar(result))
    }
}

//! Array operations: reshape, transpose, element-wise arithmetic.

use crate::dense::DenseArray;
use crate::error::ArrayError;
use crate::shape::Shape;

impl DenseArray {
    /// Reshape to a new shape, preserving element order.
    ///
    /// Succeeds only when the new shape has the same element count.
    pub fn reshape(&self, new_shape: Shape) -> Result<DenseArray, ArrayError> {
        let source = self.elem_count();
        let target = new_shape.elem_count();
        if source != target {
            return Err(ArrayError::ShapeMismatch { source, target });
        }
        Ok(DenseArray {
            shape: new_shape,
            data: self.data.clone(),
        })
    }

    /// Transpose: reverse axis order and reorder data to row-major.
    ///
    /// - Scalar/vector: returns a clone (identity).
    /// - Matrix and higher: reverses dims and physically reorders data.
    #[must_use]
    pub fn transpose(&self) -> DenseArray {
        let dims = self.shape().dims();
        if dims.len() <= 1 {
            return self.clone();
        }

        let new_dims: Vec<usize> = dims.iter().rev().copied().collect();
        let new_shape = Shape::new(new_dims);
        let n = self.elem_count();
        let mut new_data = vec![0.0; n];

        let rank = dims.len();
        let old_strides = compute_strides(dims);
        let new_strides = compute_strides(new_shape.dims());

        for flat in 0..n {
            let mut remainder = flat;
            let mut new_flat = 0;
            for axis in 0..rank {
                let idx = remainder / old_strides[axis];
                remainder %= old_strides[axis];
                new_flat += idx * new_strides[rank - 1 - axis];
            }
            new_data[new_flat] = self.data[flat];
        }

        DenseArray {
            shape: new_shape,
            data: new_data,
        }
    }
}

impl DenseArray {
    /// Apply a binary operation element-wise with scalar broadcasting.
    ///
    /// - Same shape: element-wise.
    /// - One scalar: broadcast to the other's shape.
    /// - Otherwise: ShapeMismatch error.
    pub fn apply_binop(
        &self,
        other: &DenseArray,
        op: fn(f64, f64) -> f64,
    ) -> Result<DenseArray, ArrayError> {
        if self.shape() == other.shape() {
            let data: Vec<f64> = self
                .data()
                .iter()
                .zip(other.data().iter())
                .map(|(a, b)| op(*a, *b))
                .collect();
            return Ok(DenseArray {
                shape: self.shape.clone(),
                data,
            });
        }
        // Scalar broadcast
        if self.rank() == 0 {
            let s = self.data()[0];
            let data: Vec<f64> = other.data().iter().map(|b| op(s, *b)).collect();
            return Ok(DenseArray {
                shape: other.shape.clone(),
                data,
            });
        }
        if other.rank() == 0 {
            let s = other.data()[0];
            let data: Vec<f64> = self.data().iter().map(|a| op(*a, s)).collect();
            return Ok(DenseArray {
                shape: self.shape.clone(),
                data,
            });
        }
        Err(ArrayError::ShapeMismatch {
            source: self.elem_count(),
            target: other.elem_count(),
        })
    }
}

impl DenseArray {
    /// Dot product of two rank-1 vectors.
    ///
    /// Both must be vectors of the same length. Returns a scalar.
    pub fn dot(&self, other: &DenseArray) -> Result<DenseArray, ArrayError> {
        if self.rank() != 1 || other.rank() != 1 {
            return Err(ArrayError::RankMismatch {
                expected: 1,
                got: if self.rank() != 1 {
                    self.rank()
                } else {
                    other.rank()
                },
            });
        }
        if self.elem_count() != other.elem_count() {
            return Err(ArrayError::ShapeMismatch {
                source: self.elem_count(),
                target: other.elem_count(),
            });
        }
        let sum: f64 = self
            .data()
            .iter()
            .zip(other.data().iter())
            .map(|(a, b)| a * b)
            .sum();
        Ok(DenseArray::from_scalar(sum))
    }
}

impl DenseArray {
    /// Matrix multiplication.
    ///
    /// - [m, k] * [k, n] -> [m, n]
    /// - [m, k] * [k] -> [m] (matrix-vector product)
    pub fn matmul(&self, other: &DenseArray) -> Result<DenseArray, ArrayError> {
        let (m, k) = match self.shape().dims() {
            [m, k] => (*m, *k),
            _ => {
                return Err(ArrayError::RankMismatch {
                    expected: 2,
                    got: self.rank(),
                });
            }
        };
        match other.shape().dims() {
            [k2, n] if *k2 == k => {
                let n = *n;
                let data: Vec<f64> = self
                    .data
                    .chunks(k)
                    .flat_map(|row| {
                        (0..n).map(move |j| {
                            row.iter()
                                .zip(other.data.chunks(n).map(|col| col[j]))
                                .map(|(a, b)| a * b)
                                .sum::<f64>()
                        })
                    })
                    .collect();
                Ok(DenseArray {
                    shape: Shape::new(vec![m, n]),
                    data,
                })
            }
            [k2] if *k2 == k => {
                let data: Vec<f64> = self
                    .data
                    .chunks(k)
                    .map(|row| row.iter().zip(other.data.iter()).map(|(a, b)| a * b).sum())
                    .collect();
                Ok(DenseArray {
                    shape: Shape::vector(m),
                    data,
                })
            }
            _ => Err(ArrayError::ShapeMismatch {
                source: k,
                target: other.shape().dims().first().copied().unwrap_or(0),
            }),
        }
    }
}

impl DenseArray {
    /// Reduce along an axis using the given binary operation.
    ///
    /// Removes the specified axis from the shape. For example,
    /// a [2,3] array reduced along axis 0 produces a [3] result.
    pub fn reduce_axis(
        &self,
        axis: usize,
        identity: f64,
        op: fn(f64, f64) -> f64,
    ) -> Result<DenseArray, ArrayError> {
        let dims = self.shape().dims();
        if axis >= dims.len() {
            return Err(ArrayError::IndexOutOfBounds {
                axis,
                index: axis,
                size: dims.len(),
            });
        }
        let mut result_dims: Vec<usize> = dims.to_vec();
        result_dims.remove(axis);
        let result_shape = Shape::new(result_dims);
        let result_count = result_shape.elem_count();
        let mut result_data = vec![identity; result_count];

        let strides = compute_strides(dims);
        let axis_size = dims[axis];
        let axis_stride = strides[axis];

        for flat in 0..self.elem_count() {
            let result_flat = if axis_stride > 1 {
                let outer = flat / (axis_size * axis_stride);
                let inner = flat % axis_stride;
                outer * axis_stride + inner
            } else {
                flat / axis_size
            };
            result_data[result_flat] = op(result_data[result_flat], self.data[flat]);
        }

        Ok(DenseArray {
            shape: result_shape,
            data: result_data,
        })
    }
}

impl DenseArray {
    /// Argmax along an axis. Returns an array with the given axis
    /// removed whose values are the indices (as f64) of the maxima.
    /// Ties go to the first occurrence.
    pub fn argmax_axis(&self, axis: usize) -> Result<DenseArray, ArrayError> {
        let dims = self.shape().dims();
        if axis >= dims.len() {
            return Err(ArrayError::IndexOutOfBounds {
                axis,
                index: axis,
                size: dims.len(),
            });
        }
        let mut result_dims: Vec<usize> = dims.to_vec();
        result_dims.remove(axis);
        let result_shape = Shape::new(result_dims);
        let result_count = result_shape.elem_count();
        let mut best_val = vec![f64::NEG_INFINITY; result_count];
        let mut best_idx = vec![0.0f64; result_count];

        let strides = compute_strides(dims);
        let axis_size = dims[axis];
        let axis_stride = strides[axis];

        for flat in 0..self.elem_count() {
            let result_flat = if axis_stride > 1 {
                let outer = flat / (axis_size * axis_stride);
                let inner = flat % axis_stride;
                outer * axis_stride + inner
            } else {
                flat / axis_size
            };
            // Recover axis index: (flat / axis_stride) % axis_size.
            let axis_idx = (flat / axis_stride) % axis_size;
            let v = self.data()[flat];
            if v > best_val[result_flat] {
                best_val[result_flat] = v;
                best_idx[result_flat] = axis_idx as f64;
            }
        }

        Ok(DenseArray::new(result_shape, best_idx)?)
    }
}

/// Compute strides for row-major layout.
fn compute_strides(dims: &[usize]) -> Vec<usize> {
    let mut strides = vec![1; dims.len()];
    for i in (0..dims.len().saturating_sub(1)).rev() {
        strides[i] = strides[i + 1] * dims[i + 1];
    }
    strides
}

